def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 6):
            term = ((-1) ** (j+1)) * (ratio ** j) / j
            if j % 2 == 0:
                term *= (1 + 0.1 * j)
            else:
                term *= (1 - 0.05 * j)
            score += term
        if capacity < item * 1.2:
            score *= 3
            for k in range(2):
                score += (-1)**k * (ratio ** (k+1)) * 0.1
        elif capacity < item * 2:
            score *= 1.5
            for k in range(3):
                score -= ((-1)**k) * (ratio ** (k+2)) * 0.05
        elif capacity > item * 4:
            score /= 3
            for k in range(1,4):
                if k % 2 == 0:
                    score += (ratio ** k) * 0.02
                else:
                    score -= (ratio ** k) * 0.03
        else:
            for k in range(1, 5):
                if capacity % k == 0:
                    score += 0.01 * k
                else:
                    score -= 0.005 * k
        if score < 0:
            priorities[i] = -score * (1 + ratio)
        else:
            priorities[i] = score / (1 + ratio)
    return priorities
